    // 2Y Buy USD 1mm INDEX [0.03-0.07] / 1.5% : 21Jan18-21Jan20
    CdsIndex index = product.getUnderlyingIndex();
    StringBuilder buf = new StringBuilder(96);
    buf.append(SummarizerUtils.datePeriod(index.getPaymentSchedule().getStartDate(),
        index.getPaymentSchedule().getEndDate()));
    buf.append(' ');
    buf.append(index.getBuySell());
    buf.append(' ');
    buf.append(SummarizerUtils.amount(index.getCurrency(), index.getNotional()));
    buf.append(' ');
    buf.append(index.getCdsIndexId().getValue());
    buf.append(" [");
    buf.append(SummarizerUtils.percent(product.getAttachmentPoint()));
    buf.append('-');
    buf.append(SummarizerUtils.percent(product.getDetachmentPoint()));
    buf.append("] / ");
    buf.append(SummarizerUtils.percent(index.getFixedRate()));
    buf.append(" : ");
    buf.append(SummarizerUtils.dateRange(index.getPaymentSchedule().getStartDate(),
        index.getPaymentSchedule().getEndDate()));
    return SummarizerUtils.summary(this, ProductType.CDS_INDEX, buf.toString(), index.getCurrency());
  }

