    49→public class CdsIndexTest {
    50→  private static final ReferenceData REF_DATA = ReferenceData.standard();
    51→  private static final HolidayCalendarId CALENDAR = HolidayCalendarIds.SAT_SUN;
    52→  private static final DaysAdjustment SETTLE_DAY_ADJ = DaysAdjustment.ofBusinessDays(3, CALENDAR);
    53→  private static final DaysAdjustment STEPIN_DAY_ADJ = DaysAdjustment.ofCalendarDays(1);
    54→  private static final StandardId INDEX_ID = StandardId.of("OG", "AA-INDEX");
    55→  private static final ImmutableList<StandardId> LEGAL_ENTITIES = ImmutableList.of(
    56→      StandardId.of("OG", "ABC1"), StandardId.of("OG", "ABC2"), StandardId.of("OG", "ABC3"), StandardId.of("OG", "ABC4"));
    57→  private static final double COUPON = 0.05;
    58→  private static final double NOTIONAL = 1.0e9;
    59→  private static final LocalDate START_DATE = LocalDate.of(2013, 12, 20);
    60→  private static final LocalDate END_DATE = LocalDate.of(2024, 9, 20);
    61→  private static final CdsIndex PRODUCT = CdsIndex.of(
    62→      BUY, INDEX_ID, LEGAL_ENTITIES, USD, NOTIONAL, START_DATE, END_DATE, P3M, SAT_SUN, COUPON);
    63→
    64→  @Test
    65→  public void test_builder() {
    66→    LocalDate startDate = LocalDate.of(2014, 12, 20);
    67→    LocalDate endDate = LocalDate.of(2020, 10, 20);
    68→    PeriodicSchedule sch =
    69→        PeriodicSchedule.of(startDate, endDate, P3M, BusinessDayAdjustment.NONE, SHORT_INITIAL, RollConventions.NONE);
    70→    CdsIndex test = CdsIndex.builder()
    71→        .paymentSchedule(sch)
    72→        .buySell(SELL)
    73→        .currency(JPY)
    74→        .dayCount(ACT_365F)
    75→        .fixedRate(COUPON)
    76→        .cdsIndexId(INDEX_ID)
    77→        .legalEntityIds(LEGAL_ENTITIES)
    78→        .notional(NOTIONAL)
    79→        .paymentOnDefault(PaymentOnDefault.NONE)
    80→        .protectionStart(ProtectionStartOfDay.NONE)
    81→        .settlementDateOffset(SETTLE_DAY_ADJ)
    82→        .stepinDateOffset(STEPIN_DAY_ADJ)
    83→        .build();
    84→    assertThat(test.getPaymentSchedule()).isEqualTo(sch);
    85→    assertThat(test.getBuySell()).isEqualTo(SELL);
    86→    assertThat(test.getCurrency()).isEqualTo(JPY);
    87→    assertThat(test.getDayCount()).isEqualTo(ACT_365F);
    88→    assertThat(test.getFixedRate()).isEqualTo(COUPON);
    89→    assertThat(test.getCdsIndexId()).isEqualTo(INDEX_ID);
    90→    assertThat(test.getLegalEntityIds()).isEqualTo(LEGAL_ENTITIES);
    91→    assertThat(test.getNotional()).isEqualTo(NOTIONAL);
    92→    assertThat(test.getPaymentOnDefault()).isEqualTo(PaymentOnDefault.NONE);
    93→    assertThat(test.getProtectionStart()).isEqualTo(ProtectionStartOfDay.NONE);
    94→    assertThat(test.getSettlementDateOffset()).isEqualTo(SETTLE_DAY_ADJ);
    95→    assertThat(test.getStepinDateOffset()).isEqualTo(STEPIN_DAY_ADJ);
    96→    assertThat(test.isCrossCurrency()).isFalse();
    97→    assertThat(test.allPaymentCurrencies()).containsOnly(JPY);
    98→    assertThat(test.allCurrencies()).containsOnly(JPY);
    99→  }
