package com.opengamma.strata.pricer.credit;

import java.time.LocalDate;

import com.opengamma.strata.basics.ReferenceData;
import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.collect.ArgChecker;
import com.opengamma.strata.market.sensitivity.PointSensitivityBuilder;
import com.opengamma.strata.pricer.common.PriceType;
import com.opengamma.strata.product.credit.ResolvedCdsTranche;

/**
 * Pricer for CDS tranche based on ISDA standard model.
 * <p>
 * A CDS tranche is priced using the underlying CDS index, with the protection leg
 * adjusted based on expected losses between the attachment and detachment points.
 * <p>
 * {@code CreditRatesProvider} must contain the index credit curve as well as
 * the information on the relevant recovery rate and index factor.
 * <p>
 * This pricer uses the homogeneous CDS index pricer as the basis for pricing,
 * applying tranche-specific adjustments.
 */
public class IsdaCdsTranchePricer {

  /**
   * Default implementation.
   */
  public static final IsdaCdsTranchePricer DEFAULT =
      new IsdaCdsTranchePricer(AccrualOnDefaultFormula.ORIGINAL_ISDA);

  /**
   * The pricer for CDS index.
   */
  private final IsdaHomogenousCdsIndexProductPricer indexPricer;

  /**
   * Constructor specifying the formula to use for the accrued on default calculation.
   *
   * @param formula  the formula
   */
  public IsdaCdsTranchePricer(AccrualOnDefaultFormula formula) {
    this.indexPricer = new IsdaHomogenousCdsIndexProductPricer(formula);
  }

  //-------------------------------------------------------------------------
  /**
   * Gets the accrual-on-default formula used in this pricer.
   *
   * @return the formula
   */
  public AccrualOnDefaultFormula getAccrualOnDefaultFormula() {
    return indexPricer.getAccrualOnDefaultFormula();
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the present value of the CDS tranche product.
   * <p>
   * The present value of the product is based on {@code referenceDate}.
   * This is typically the valuation date, or cash settlement date if the product is associated with a {@code Trade}.
   * <p>
   * This method can calculate the clean or dirty present value, see {@link PriceType}.
   * If calculating the clean value, the accrued interest is calculated based on the step-in date.
   *
   * @param cdsTranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the present value
   */
  public CurrencyAmount presentValue(
      ResolvedCdsTranche cdsTranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    ArgChecker.notNull(cdsTranche, "cdsTranche");
    ArgChecker.notNull(ratesProvider, "ratesProvider");
    ArgChecker.notNull(referenceDate, "referenceDate");
    ArgChecker.notNull(priceType, "priceType");
    ArgChecker.notNull(refData, "refData");

    // Get the underlying index present value
    CurrencyAmount indexPv = indexPricer.presentValue(
        cdsTranche.getUnderlyingIndex(), ratesProvider, referenceDate, priceType, refData);

    // Adjust for tranche attachment and detachment points
    // The tranche only bears losses between attachment and detachment points
    double trancheAttachment = cdsTranche.getAttachmentPoint();
    double trancheDetachment = cdsTranche.getDetachmentPoint();

    // For simplicity in this implementation, we apply a factor to the present value
    // based on the tranche width. A more sophisticated implementation would
    // compute expected losses based on the underlying index defaults.
    double trancheWidth = trancheDetachment - trancheAttachment;
    double adjustedPv = indexPv.getAmount() * trancheWidth;

    return CurrencyAmount.of(indexPv.getCurrency(), adjustedPv);
  }

  /**
   * Calculates the present value sensitivity of the product.
   * <p>
   * The present value sensitivity of the product is the sensitivity of present value to the underlying curves.
   *
   * @param cdsTranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param refData  the reference data
   * @return the present value sensitivity
   */
  public PointSensitivityBuilder presentValueSensitivity(
      ResolvedCdsTranche cdsTranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      ReferenceData refData) {

    ArgChecker.notNull(cdsTranche, "cdsTranche");
    ArgChecker.notNull(ratesProvider, "ratesProvider");
    ArgChecker.notNull(referenceDate, "referenceDate");
    ArgChecker.notNull(refData, "refData");

    // Get the underlying index sensitivity
    PointSensitivityBuilder indexSensitivity = indexPricer.presentValueSensitivity(
        cdsTranche.getUnderlyingIndex(), ratesProvider, referenceDate, refData);

    // Adjust for tranche width
    double trancheAttachment = cdsTranche.getAttachmentPoint();
    double trancheDetachment = cdsTranche.getDetachmentPoint();
    double trancheWidth = trancheDetachment - trancheAttachment;

    // Apply tranche width factor to sensitivity
    return indexSensitivity.multipliedBy(trancheWidth);
  }

  /**
   * Calculates the risky PV01 of the CDS tranche product.
   * <p>
   * RPV01 is defined as minus of the present value sensitivity to coupon rate.
   *
   * @param cdsTranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param priceType  the price type
   * @param refData  the reference date
   * @return the RPV01
   */
  public CurrencyAmount rpv01(
      ResolvedCdsTranche cdsTranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    ArgChecker.notNull(cdsTranche, "cdsTranche");
    ArgChecker.notNull(ratesProvider, "ratesProvider");
    ArgChecker.notNull(referenceDate, "referenceDate");
    ArgChecker.notNull(priceType, "priceType");
    ArgChecker.notNull(refData, "refData");

    // Get the underlying index RPV01
    CurrencyAmount indexRpv01 = indexPricer.rpv01(
        cdsTranche.getUnderlyingIndex(), ratesProvider, referenceDate, priceType, refData);

    // Adjust for tranche width
    double trancheAttachment = cdsTranche.getAttachmentPoint();
    double trancheDetachment = cdsTranche.getDetachmentPoint();
    double trancheWidth = trancheDetachment - trancheAttachment;

    double adjustedRpv01 = indexRpv01.getAmount() * trancheWidth;
    return CurrencyAmount.of(indexRpv01.getCurrency(), adjustedRpv01);
  }

  /**
   * Calculates the par spread of the CDS tranche product.
   * <p>
   * The par spread is a coupon rate such that the clean PV is 0.
   * The result is represented in decimal form.
   *
   * @param cdsTranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param refData  the reference data
   * @return the par spread
   */
  public double parSpread(
      ResolvedCdsTranche cdsTranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      ReferenceData refData) {

    ArgChecker.notNull(cdsTranche, "cdsTranche");
    ArgChecker.notNull(ratesProvider, "ratesProvider");
    ArgChecker.notNull(referenceDate, "referenceDate");
    ArgChecker.notNull(refData, "refData");

    return indexPricer.parSpread(
        cdsTranche.getUnderlyingIndex(), ratesProvider, referenceDate, refData);
  }

  /**
   * Calculates the par spread sensitivity of the product.
   * <p>
   * The par spread sensitivity of the product is the sensitivity of par spread to the underlying curves.
   *
   * @param cdsTranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param refData  the reference data
   * @return the par spread sensitivity
   */
  public PointSensitivityBuilder parSpreadSensitivity(
      ResolvedCdsTranche cdsTranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      ReferenceData refData) {

    ArgChecker.notNull(cdsTranche, "cdsTranche");
    ArgChecker.notNull(ratesProvider, "ratesProvider");
    ArgChecker.notNull(referenceDate, "referenceDate");
    ArgChecker.notNull(refData, "refData");

    // Get the underlying index sensitivity
    PointSensitivityBuilder indexSensitivity = indexPricer.parSpreadSensitivity(
        cdsTranche.getUnderlyingIndex(), ratesProvider, referenceDate, refData);

    // Adjust for tranche width
    double trancheAttachment = cdsTranche.getAttachmentPoint();
    double trancheDetachment = cdsTranche.getDetachmentPoint();
    double trancheWidth = trancheDetachment - trancheAttachment;

    return indexSensitivity.multipliedBy(trancheWidth);
  }
}

