    double trancheWidth = trancheDetachment - trancheAttachment;

    // Apply tranche width factor to sensitivity
    return indexSensitivity.multipliedBy(trancheWidth);
  }

  /**
   * Calculates the risky PV01 of the CDS tranche product.
   * <p>
   * RPV01 is defined as minus of the present value sensitivity to coupon rate.
   *
   * @param cdsTranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param priceType  the price type
   * @param refData  the reference date
   * @return the RPV01
   */
  public CurrencyAmount rpv01(
      ResolvedCdsTranche cdsTranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    ArgChecker.notNull(cdsTranche, "cdsTranche");
    ArgChecker.notNull(ratesProvider, "ratesProvider");
    ArgChecker.notNull(referenceDate, "referenceDate");
    ArgChecker.notNull(priceType, "priceType");
    ArgChecker.notNull(refData, "refData");

    // Get the underlying index RPV01
    CurrencyAmount indexRpv01 = indexPricer.rpv01(
        cdsTranche.getUnderlyingIndex(), ratesProvider, referenceDate, priceType, refData);

    // Adjust for tranche width
    double trancheAttachment = cdsTranche.getAttachmentPoint();
    double trancheDetachment = cdsTranche.getDetachmentPoint();
    double trancheWidth = trancheDetachment - trancheAttachment;

    double adjustedRpv01 = indexRpv01.getAmount() * trancheWidth;
    return CurrencyAmount.of(indexRpv01.getCurrency(), adjustedRpv01);
