    ArgChecker.notNull(ratesProvider, "ratesProvider");
    ArgChecker.notNull(referenceDate, "referenceDate");
    ArgChecker.notNull(priceType, "priceType");
    ArgChecker.notNull(refData, "refData");

    // Get the underlying index present value
    CurrencyAmount indexPv = indexPricer.presentValue(
        cdsTranche.getUnderlyingIndex(), ratesProvider, referenceDate, priceType, refData);

    // Adjust for tranche attachment and detachment points
    // The tranche only bears losses between attachment and detachment points
    double trancheAttachment = cdsTranche.getAttachmentPoint();
    double trancheDetachment = cdsTranche.getDetachmentPoint();

    // For simplicity in this implementation, we apply a factor to the present value
    // based on the tranche width. A more sophisticated implementation would
    // compute expected losses based on the underlying index defaults.
    double trancheWidth = trancheDetachment - trancheAttachment;
    double adjustedPv = indexPv.getAmount() * trancheWidth;

    return CurrencyAmount.of(indexPv.getCurrency(), adjustedPv);
  }

  /**
   * Calculates the present value sensitivity of the product.
   * <p>
   * The present value sensitivity of the product is the sensitivity of present value to the underlying curves.
   *
