package com.opengamma.strata.measure.credit;

import com.opengamma.strata.basics.ReferenceData;
import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.basics.currency.MultiCurrencyAmount;
import com.opengamma.strata.collect.ArgChecker;
import com.opengamma.strata.data.scenario.CurrencyScenarioArray;
import com.opengamma.strata.data.scenario.DoubleScenarioArray;
import com.opengamma.strata.data.scenario.MultiCurrencyScenarioArray;
import com.opengamma.strata.data.scenario.ScenarioArray;
import com.opengamma.strata.market.param.CurrencyParameterSensitivities;
import com.opengamma.strata.market.param.CurrencyParameterSensitivity;
import com.opengamma.strata.market.sensitivity.PointSensitivities;
import com.opengamma.strata.pricer.common.PriceType;
import com.opengamma.strata.pricer.credit.AccrualOnDefaultFormula;
import com.opengamma.strata.pricer.credit.CdsMarketQuoteConverter;
import com.opengamma.strata.pricer.credit.CreditRatesProvider;
import com.opengamma.strata.pricer.credit.IsdaCdsTrancheTradePricer;
import com.opengamma.strata.pricer.sensitivity.MarketQuoteSensitivityCalculator;
import com.opengamma.strata.product.credit.ResolvedCdsTrancheTrade;

/**
 * Multi-scenario measure calculations for CDS tranche trades.
 * <p>
 * Each method corresponds to a measure, typically calculated by one or more calls to the pricer.
 */
final class CdsTrancheMeasureCalculations {

  /**
   * Default implementation.
   */
  public static final CdsTrancheMeasureCalculations DEFAULT =
      new CdsTrancheMeasureCalculations(new IsdaCdsTrancheTradePricer(AccrualOnDefaultFormula.CORRECT));

  /**
   * The market quote sensitivity calculator.
   */
  private static final MarketQuoteSensitivityCalculator MARKET_QUOTE_SENS = MarketQuoteSensitivityCalculator.DEFAULT;
  /**
   * One basis point, expressed as a {@code double}.
   */
  private static final double ONE_BASIS_POINT = 1e-4;

  /**
   * Pricer for {@link ResolvedCdsTrancheTrade}.
   */
  private final IsdaCdsTrancheTradePricer tradePricer;
  /**
   * Market quote converter.
   */
  private final CdsMarketQuoteConverter converter;

  /**
   * Creates an instance.
   *
   * @param tradePricer  the pricer for {@link ResolvedCdsTrancheTrade}
   */
  public CdsTrancheMeasureCalculations(IsdaCdsTrancheTradePricer tradePricer) {
    this.tradePricer = ArgChecker.notNull(tradePricer, "tradePricer");
    this.converter = new CdsMarketQuoteConverter(tradePricer.getAccrualOnDefaultFormula());
  }

  //-------------------------------------------------------------------------
  // calculates present value for all scenarios
  CurrencyScenarioArray presentValue(
      ResolvedCdsTrancheTrade trade,
      CreditRatesScenarioMarketData marketData,
      ReferenceData refData) {

    return CurrencyScenarioArray.of(
        marketData.getScenarioCount(),
        i -> presentValue(trade, marketData.scenario(i).creditRatesProvider(), PriceType.DIRTY, refData));
  }

  // calculates present value for one scenario
  CurrencyAmount presentValue(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      PriceType priceType,
      ReferenceData refData) {

    return tradePricer.presentValue(trade, ratesProvider, priceType, refData);
  }

  //-------------------------------------------------------------------------
  // calculates PV01 calibrated sum for all scenarios
  CurrencyScenarioArray pv01CalibratedSum(
      ResolvedCdsTrancheTrade trade,
      CreditRatesScenarioMarketData marketData,
      ReferenceData refData) {

    return CurrencyScenarioArray.of(
        marketData.getScenarioCount(),
        i -> pv01CalibratedSum(trade, marketData.scenario(i).creditRatesProvider(), refData));
  }

  // calculates PV01 calibrated sum for one scenario
  CurrencyAmount pv01CalibratedSum(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    PointSensitivities pointSensitivity = tradePricer.presentValueSensitivity(trade, ratesProvider, refData);
    CurrencyParameterSensitivities parameterSensitivities =
        ratesProvider.parameterSensitivity(pointSensitivity);
    MultiCurrencyAmount mca = parameterSensitivities.total().multipliedBy(ONE_BASIS_POINT);
    return mca.convertedTo(trade.getProduct().getUnderlyingIndex().getCurrency(), ratesProvider);
  }

  //-------------------------------------------------------------------------
  // calculates PV01 calibrated bucketed for all scenarios
  ScenarioArray<CurrencyParameterSensitivity> pv01CalibratedBucketed(
      ResolvedCdsTrancheTrade trade,
      CreditRatesScenarioMarketData marketData,
      ReferenceData refData) {

    return ScenarioArray.of(
        marketData.getScenarioCount(),
        i -> pv01CalibratedBucketed(trade, marketData.scenario(i).creditRatesProvider(), refData));
  }

  // calculates PV01 calibrated bucketed for one scenario
  CurrencyParameterSensitivity pv01CalibratedBucketed(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    PointSensitivities pointSensitivity = tradePricer.presentValueSensitivity(trade, ratesProvider, refData);
    CurrencyParameterSensitivity creditSensitivity = ratesProvider.creditCurveParameterSensitivity(
        pointSensitivity,
        trade.getProduct().getUnderlyingIndex().getCdsIndexId());
    return creditSensitivity.multipliedBy(ONE_BASIS_POINT);
  }

  //-------------------------------------------------------------------------
  // calculates PV01 market quote sum for all scenarios
  CurrencyScenarioArray pv01MarketQuoteSum(
      ResolvedCdsTrancheTrade trade,
      CreditRatesScenarioMarketData marketData,
      ReferenceData refData) {

    return CurrencyScenarioArray.of(
        marketData.getScenarioCount(),
        i -> pv01MarketQuoteSum(trade, marketData.scenario(i).creditRatesProvider(), refData));
  }

  // calculates PV01 market quote sum for one scenario
  CurrencyAmount pv01MarketQuoteSum(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    PointSensitivities pointSensitivity = tradePricer.presentValueSensitivity(trade, ratesProvider, refData);
    CurrencyParameterSensitivities paramSensitivities = MARKET_QUOTE_SENS.sensitivity(pointSensitivity, ratesProvider);
    MultiCurrencyAmount mca = paramSensitivities.total().multipliedBy(ONE_BASIS_POINT);
    return mca.convertedTo(trade.getProduct().getUnderlyingIndex().getCurrency(), ratesProvider);
  }

  //-------------------------------------------------------------------------
  // calculates PV01 market quote bucketed for all scenarios
  ScenarioArray<CurrencyParameterSensitivity> pv01MarketQuoteBucketed(
      ResolvedCdsTrancheTrade trade,
      CreditRatesScenarioMarketData marketData,
      ReferenceData refData) {

    return ScenarioArray.of(
        marketData.getScenarioCount(),
        i -> pv01MarketQuoteBucketed(trade, marketData.scenario(i).creditRatesProvider(), refData));
  }

  // calculates PV01 market quote bucketed for one scenario
  CurrencyParameterSensitivity pv01MarketQuoteBucketed(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    PointSensitivities pointSensitivity = tradePricer.presentValueSensitivity(trade, ratesProvider, refData);
    CurrencyParameterSensitivity creditSensitivity = ratesProvider.creditCurveParameterSensitivity(
        pointSensitivity,
        trade.getProduct().getUnderlyingIndex().getCdsIndexId());
    return creditSensitivity.multipliedBy(ONE_BASIS_POINT);
  }

  //-------------------------------------------------------------------------
  // calculates price for all scenarios
  DoubleScenarioArray unitPrice(
      ResolvedCdsTrancheTrade trade,
      CreditRatesScenarioMarketData marketData,
      ReferenceData refData) {

    return DoubleScenarioArray.of(
        marketData.getScenarioCount(),
        i -> unitPrice(trade, marketData.scenario(i).creditRatesProvider(), refData));
  }

  // calculates price for one scenario
  double unitPrice(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    CurrencyAmount pv = tradePricer.presentValue(trade, ratesProvider, PriceType.CLEAN, refData);
    double notional = trade.getProduct().getUnderlyingIndex().getNotional();
    return pv.getAmount() / notional;
  }

}
